SELECT count(*) FROM keyword, movie_keyword, title, kind_type, movie_info, info_type, movie_companies WHERE movie_keyword.keyword_id = keyword.id AND movie_keyword.movie_id = title.id AND title.kind_id = kind_type.id AND movie_info.movie_id = title.id AND movie_info.info_type_id = info_type.id AND movie_companies.movie_id = title.id;